# Filtra solo CE (Conto Economico)
df_ce = df_input[df_input['CE/SP'] == 'CE'].copy()

# Raggruppa per Riclassifica Sintetica e Mese_Anno, somma i Saldi
ce_data = df_ce.groupby(['Riclassifica Sintetica', 'Mese_Anno'])['Saldo (D-A)'].sum().reset_index()

# Crea pivot table
pivot_ce = ce_data.pivot_table(
    index='Riclassifica Sintetica',
    columns='Mese_Anno',
    values='Saldo (D-A)',
    aggfunc='sum'
)

# Ordina le colonne per data
pivot_ce = pivot_ce.reindex(sorted(pivot_ce.columns, key=lambda x: pd.to_datetime(x, format='%m/%Y')), axis=1)

# Arrotonda a 2 decimali
pivot_ce = pivot_ce.round(2)

# Prepara i dati dettagliati per l'espansione
detail_data = df_ce.groupby(['Riclassifica Sintetica', 'Mese_Anno', 'Descr. Conto'])['Saldo (D-A)'].sum().reset_index()

# Converti in formato JSON
