for _, row in detail_data.iterrows():
    key = f"{row['Riclassifica Sintetica']}_{row['Mese_Anno']}"
    if key not in detail_dict:
        detail_dict[key] = []
    detail_dict[key].append({
        'Descr. Conto': row['Descr. Conto'],
        'Saldo (D-A)': round(row['Saldo (D-A)'], 2)
    })

# Converti pivot_ce in dict corretto
pivot_dict = {}
for idx in pivot_ce.index:
    pivot_dict[idx] = {}
    for col in pivot_ce.columns:
        val = pivot_ce.loc[idx, col]
        pivot_dict[idx][col] = float(val) if pd.notna(val) else 0.0

# Estrai lista unica di mesi ordinati
all_months = sorted(pivot_ce.columns.tolist(), key=lambda x: pd.to_datetime(x, format='%m/%Y'))

json_details = json.dumps(detail_dict, default=str)
json_columns = json.dumps(all_months, default=str)
json_index = json.dumps(pivot_ce.index.tolist(), default=str)
